def sort_matrix(matrix):
    # Sort the matrix based on the sum of its rows.
    n = len(matrix)
    for i in range(1, n): 
        sum_row = 0 
        for j in range(len(matrix)): 
            sum_row += matrix[j][0] 
        # sort the matrix according to the sum of its rows.
        for k in range(n): 
            if(sum_row - matrix[k][0] == 0): 
                matrix[k].append([sum_row - matrix[k][0]] 
                    for i in range(n) 
                    if i != k) 
        return matrix

