    res = []
    for i in range(1, n+1):
        # If there is no character without replacement
        if (string[i] == ' '):
            # If there are more than one possible string
            for j in range(i-1, n-i-1, -1):
                res.append(j-i)
            # If there are more than one possible string
            for j in range(i+1, n+1, -1):
                res.append(j-i)
