def max_sub_array_sum_repeated(array, k):
    # initialize with all elements set to 0
    result = [0]
    for i in range(len(array)-k+1):
        # store the current sum
        current_sum = array[i]

        # loop over the k times the current sum
        for j in range(k):
            # add the current sum to the sum that was stored at the previous iteration
