def max_subarray_product(arr):
    if len(arr) == 0:
        return 0
    # check if array elements are positive numbers 
    for i in range(len(arr)):
        if arr[i] < 0:
            return -max_subarray_product(arr)
    # check if we have found the maximum product 
    for i in range(1, len(arr)):
        m = min(arr[i], arr[i - 1])
        max_val = max(arr[0 : i - 1])
        if max_val * m > arr[i]:
